// TestIntakeBlockedCarriesRuleFingerprint asserts every intake.blocked entry
// emitted by readiness has a non-empty rule_fingerprint stable across reruns
// with identical inputs.
func TestIntakeBlockedCarriesRuleFingerprint(t *testing.T) {
	inner, _, _ := newExecuteLoopTestStore(t)
	store := &parkCountingStore{claimCountingStore: &claimCountingStore{Store: inner}}

	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			return ExecuteBeadReport{
				BeadID:    beadID,
				Status:    ExecuteBeadStatusSuccess,
				SessionID: "sess-fingerprint",
				ResultRev: "fingerprint",
			}, nil
		}),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	// First run - operator required outcome
	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
		Once:         true,
		TargetBeadID: "ddx-0001",
		PreClaimIntakeHook: func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
			return PreClaimIntakeResult{
				Outcome: PreClaimIntakeOperatorRequired,
				Reason:  "test_rule",
				Detail:  "needs operator review",
			}, nil
		},
	})
	require.NoError(t, err)
	require.NotNil(t, result)

	// Check that the intake.blocked event has rule_fingerprint
	got, err := inner.Get("ddx-0001")
	require.NoError(t, err)
	events, err := inner.Events("ddx-0001")
	require.NoError(t, err)

	var intakeBlockedEvent *bead.BeadEvent
	for i := range events {
		if events[i].Kind == "intake.blocked" {
			intakeBlockedEvent = &events[i]
			break
		}
	}
	require.NotNil(t, intakeBlockedEvent, "intake.blocked event must be emitted")

	var body map[string]any
	err = json.Unmarshal([]byte(intakeBlockedEvent.Body), &body)
	require.NoError(t, err)

	ruleFingerprint, ok := body["rule_fingerprint"]
	require.True(t, ok, "rule_fingerprint must be present in intake.blocked body")
	assert.NotEmpty(t, ruleFingerprint, "rule_fingerprint must be non-empty")

	firstRunRuleFingerprint := ruleFingerprint.(string)

	// Second run with identical inputs - rule_fingerprint should be the same
	store2 := &parkCountingStore{claimCountingStore: &claimCountingStore{Store: inner}}
	worker2 := &ExecuteBeadWorker{
		Store: store2,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			return ExecuteBeadReport{
				BeadID:    beadID,
				Status:    ExecuteBeadStatusSuccess,
				SessionID: "sess-fingerprint2",
				ResultRev: "fingerprint2",
			}, nil
		}),
	}

	result2, err := worker2.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
		Once:         true,
		TargetBeadID: "ddx-0001",
		PreClaimIntakeHook: func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
			return PreClaimIntakeResult{
				Outcome: PreClaimIntakeOperatorRequired,
				Reason:  "test_rule",
				Detail:  "needs operator review",
			}, nil
		},
	})
	require.NoError(t, err)
	require.NotNil(t, result2)

	// Verify the second run produces the same rule_fingerprint
	events2, err := inner.Events("ddx-0001")
	require.NoError(t, err)

	var secondBlockedEvent *bead.BeadEvent
	blockCount := 0
	for i := range events2 {
		if events2[i].Kind == "intake.blocked" {
			secondBlockedEvent = &events2[i]
			blockCount++
		}
	}

	var body2 map[string]any
	err = json.Unmarshal([]byte(secondBlockedEvent.Body), &body2)
	require.NoError(t, err)

	ruleFingerprint2 := body2["rule_fingerprint"].(string)
